(() => {
  const facts = state.numFacts || 20;
  const actions = state.numActions || 8;
  const avgEffects = 3;
  const frameAxioms = actions * (facts - avgEffects);
  const effectAxioms = actions * avgEffects;
  const totalSTRIPS = frameAxioms + effectAxioms;
  const neuralParams = actions * facts;
  const ratio = (frameAxioms / totalSTRIPS * 100).toFixed(0);
  const bar = (val, max, char) => char.repeat(Math.round(val / max * 40));
  return `With ${facts} facts and ${actions} actions:

üìê STRIPS AXIOMS NEEDED:
   Effect axioms:  ${effectAxioms.toString().padStart(5)} ${bar(effectAxioms, totalSTRIPS, '‚ñà')}
   Frame axioms:   ${frameAxioms.toString().padStart(5)} ${bar(frameAxioms, totalSTRIPS, '‚ñë')}
   Total:          ${totalSTRIPS.toString().padStart(5)}

   ${ratio}% of all axioms just say "nothing changed"! üò±

üßÝ NEURAL OPERATORS:
   Rotation params: ${neuralParams} (each dimension handled implicitly)
   Frame axioms:    0 (unchanged dims preserved by rotation)
   Total:           ${neuralParams}

üìâ Savings: ${((1 - neuralParams/totalSTRIPS) * 100).toFixed(0)}% fewer parameters

üí° As the world gets bigger, STRIPS drowns in frame axioms.
   Neural operators scale gracefully ‚Äî O(d¬≤) per operator regardless.`;
})()

(() => {
  const scenarios = {
    restaurant: {
      title: 'Restaurant Script',
      steps: [
        { op: 'PTRANS', desc: 'Enter restaurant', state: 'location: outside‚Üíinside, hunger: high' },
        { op: 'PTRANS+GRASP', desc: 'Walk to table, sit', state: 'location: entrance‚Üítable, seated: true' },
        { op: 'MTRANS+ATRANS', desc: 'Order food (tell waiter, promise payment)', state: 'waiter.knows(order): true, commitment: pay' },
        { op: 'INGEST', desc: 'Eat the meal', state: 'hunger: high‚Üílow, food: present‚Üíconsumed' },
        { op: 'ATRANS', desc: 'Pay the bill', state: 'money: customer‚Üírestaurant, debt: cleared' }
      ]
    },
    cooking: {
      title: 'Cooking a Meal',
      steps: [
        { op: 'PTRANS', desc: 'Gather ingredients', state: 'ingredients: stored‚Üíworkspace' },
        { op: 'PROPEL+MOVE', desc: 'Chop vegetables', state: 'vegetables: whole‚Üíchopped' },
        { op: 'PROPEL(heat)', desc: 'Apply heat', state: 'temperature: cold‚Üíhot, state: raw‚Üícooking' },
        { op: 'ATTEND', desc: 'Monitor cooking', state: 'cook.knows(doneness): updating' },
        { op: 'MOVE', desc: 'Plate the dish', state: 'food: pan‚Üíplate, state: cooking‚Üífinished' }
      ]
    },
    trade: {
      title: 'Trade / Commerce',
      steps: [
        { op: 'MBUILD', desc: 'Decide to buy', state: 'buyer.intent: acquire(item)' },
        { op: 'MTRANS', desc: 'Negotiate price', state: 'agreement: forming, price: converging' },
        { op: 'ATRANS', desc: 'Transfer payment', state: 'money: buyer‚Üíseller' },
        { op: 'ATRANS', desc: 'Transfer goods', state: 'item: seller‚Üíbuyer' },
        { op: 'MBUILD', desc: 'Evaluate satisfaction', state: 'buyer.satisfaction: assessed' }
      ]
    },
    learning: {
      title: 'Learning Process',
      steps: [
        { op: 'ATTEND', desc: 'Notice something new', state: 'attention: unfocused‚Üífocused' },
        { op: 'MTRANS', desc: 'Receive information', state: 'student.knowledge: ¬¨concept‚Üíraw_input' },
        { op: 'MBUILD', desc: 'Build understanding', state: 'student.model: none‚Üípartial‚Üíintegrated' },
        { op: 'MTRANS', desc: 'Explain to someone else', state: 'other.knowledge: ¬¨concept‚Üíconcept' },
        { op: 'MBUILD', desc: 'Deeper understanding from teaching', state: 'student.model: integrated‚Üídeep' }
      ]
    }
  };
  const s = scenarios[state.scenario || 'restaurant'];
  const currentStep = Math.min(state.step || 0, s.steps.length - 1);
  let result = `‚îÅ‚îÅ‚îÅ ${s.title} ‚îÅ‚îÅ‚îÅ\n\n`;
  const composedOps = [];
  for (let i = 0; i < s.steps.length; i++) {
    const step = s.steps[i];
    const marker = i < currentStep ? '‚úÖ' : i === currentStep ? 'üëâ' : '‚¨ú';
    result += `${marker} Step ${i+1}: ${step.op}\n   ${step.desc}\n   State: ${step.state}\n\n`;
    if (i <= currentStep) composedOps.push(step.op);
  }
  result += `‚îÅ‚îÅ‚îÅ Composed Operator ‚îÅ‚îÅ‚îÅ\n`;
  result += `R_total = ${composedOps.join(' ‚àò ')}\n\n`;
